sql:
SELECT instrument_name
FROM financial_instruments
ORDER BY instrument_name ASC;

external_knowledge:
- 'most volatile trends' refers to the trends with the highest volatility, which is a measure of the dispersion of returns for a given financial instrument; 
- 'details of the financial instruments' includes the name of the instrument, trend direction, highest price, lowest price, volatility, start time, and end time; 
- '2023' refers to the time frame where both the start and end times of the trends fall within the calendar year.

sql:
SELECT instrument_id, COUNT(comment_id) AS total_comments
     FROM market_comments
     GROUP BY instrument_id;
